import React from 'react';
import './StudentTips.css';

const StudentTips = () => {
  const tips = [
    "Не недооценивай гололёд",
    "Реши вопрос с жильём ДО приезда",
    "Скачай 2ГИС — город большой",
    "Гуляй по набережной и Мосту Влюблённых",
    "Не бойся общаться — люди открытые",
    "Бери тёплую одежду, но не весь гардероб",
    "Не откладывай оформление документов",
    "Рассчитывай на автобус в отдалённых районах",
    "Не стоит быть закрытым"
  ];

  return (
    <section className="student-tips section">
      <div className="container">
        <div className="tips-grid">
          <div className="tips-card">
            <h3 className="tips-title">📝 Советы от студентов</h3>
            <ul className="tips-list">
              {tips.map((tip, idx) => (
                <li key={idx}>{tip}</li>
              ))}
            </ul>
          </div>
          <div className="testimonial-card">
            <div className="testimonial-quote">“</div>
            <p className="testimonial-text">
              Ожидания оправдались. Тюмень — класс
            </p>
            <p className="testimonial-author">— респондент из Екатеринбурга</p>
            <div className="testimonial-divider"></div>
            <p className="testimonial-note">
              Проект помогает разрушать стереотипы о Тюмени и Сибири там, 
              где государственные новости почти не работают. Университеты 
              получают простой и бесплатный инструмент адаптации иностранцев.
            </p>
          </div>
        </div>
      </div>
    </section>
  );
};

export default StudentTips;