import React, { useState, useRef, useEffect } from 'react';
import migrationSteps from '../data/migrationSteps.json';
import { AlertTriangle, MapPin, Check, Globe, HelpCircle, Download } from 'lucide-react';
import html2pdf from 'html2pdf.js';
import './MigrationGuide.css';


const CITIZENSHIP_CONFIG = {
  armenia: { label: 'Гражданин(ка) Армении', days: 30, visaNotice: false },
  kazakhstan: { label: 'Гражданин(ка) Казахстана', days: 30, visaNotice: false },
  kyrgyzstan: { label: 'Гражданин(ка) Киргизии', days: 30, visaNotice: false },
  tadzhikistan: { label: 'Гражданин(ка) Таджикистана', days: 15, visaNotice: false },
  uzbekistan: { label: 'Гражданин(ка) Узбекистана', days: 15, visaNotice: false },
  eaes_workers: { label: 'Трудящийся(ая) в РФ гражданин(ка) государства — члена ЕАЭС', days: 30, visaNotice: false },
  vks: { label: 'ВКС или член его(её) семьи (при смене места пребывания в РФ)', days: 30, visaNotice: false },
  belarus: { label: 'Гражданин(ка) Беларуси', days: 90, visaNotice: false },
  other: { label: 'Остальные иностранцы', days: 7, visaNotice: true }
};

const CalendarIcon = () => {
  const [currentTheme, setCurrentTheme] = useState('light');

  useEffect(() => {
    const htmlTheme = document.documentElement.getAttribute('data-theme');
    setCurrentTheme(htmlTheme === 'dark' ? 'dark' : 'light');

    const observer = new MutationObserver(() => {
      const newTheme = document.documentElement.getAttribute('data-theme');
      setCurrentTheme(newTheme === 'dark' ? 'dark' : 'light');
    });
    observer.observe(document.documentElement, { attributes: true });
    
    return () => observer.disconnect();
  }, []);

  const iconSrc = currentTheme === 'light' 
    ? './icons/calendar-light.png' 
    : './icons/calendar-dark.png';

  return <img src={iconSrc} alt="Актуальность" width={14} height={14} style={{ flexShrink: 0 }} />;
};

const MigrationGuide = ({ theme, language }) => {
  const [checkedSteps, setCheckedSteps] = useState({});
  const [citizenship, setCitizenship] = useState('');
  const [isExporting, setIsExporting] = useState(false);
  const contentRef = useRef(null);

  const toggleStep = (id) => {
    setCheckedSteps(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const exportToPDF = async () => {
    if (!contentRef.current) return;
    
    setIsExporting(true);
    
    const element = contentRef.current;
    const opt = {
      margin: [10, 10, 10, 10],
      filename: `Памятка_легализации_ТюмГУ_${new Date().toISOString().slice(0, 10)}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };
    
    try {
      await html2pdf().set(opt).from(element).save();
    } catch (error) {
      console.error('Ошибка при создании PDF:', error);
    } finally {
      setIsExporting(false);
    }
  };

  const getFilteredSteps = () => {
    if (!citizenship) return [];

    if (citizenship === 'belarus') {
      return [
        {
          id: 'combined_belarus',
          title: "Постановка на миграционный учёт",
          details: (
            <>
              Срок: В течение 90 дней;<br />
              В общежитии: Занимается ОПВС СоцГум. В квартире: Отдел МВД или Госуслуги (Ходатайство берется в вузе!).
            </>
          )
        },
        ...migrationSteps.filter(step => step.id >= 6)
      ];
    }

    const currentCountry = CITIZENSHIP_CONFIG[citizenship];
    
    return migrationSteps.map(step => {
      if (step.id === 2 || step.id === '2') {
        const durationText = currentCountry?.days === 7 
          ? "В течение 7 рабочих дней" 
          : `В течение ${currentCountry?.days} календарных дней`;

        return {
          ...step,
          details: (
            <>
              Срок: {durationText};<br />
              {currentCountry?.visaNotice && (
                <span className="visa-notice">
                  Внимание: Для вашей категории въезд в РФ может быть осуществлен по визе. В этом случае срок действия первой регистрации будет ограничен сроком действия визы.
                </span>
              )}
              В общежитии: Оформляет ОПВС СоцГум (ул. Ленина, 23). В квартире: МФЦ или МВД (Ходатайство обязательно берется в ОПВС!).
            </>
          )
        };
      }
      return step;
    });
  };

  const filteredSteps = getFilteredSteps();

  return (
    <section className="migration-guide section">
      <div className="container">
        {/* Заголовок по центру */}
        <div className="migration-header-centered">
          <h2 className="section-title">Памятка легализации</h2>
          <p className="section-subtitle">
            Тюменский государственный университет • актуально на 2026 год
          </p>
        </div>

        {/* Выбор гражданства */}
        <div className={`citizenship-selector-container ${citizenship === '' ? 'centered-mode' : ''}`}>
          <label htmlFor="citizenship-select" className="selector-label">
            <Globe size={16} />
            <span>Укажите ваше гражданство или статус:</span>
          </label>
          <select 
            id="citizenship-select" 
            className="citizenship-select"
            value={citizenship}
            onChange={(e) => {
              setCitizenship(e.target.value);
              setCheckedSteps({});
            }}
          >
            <option value="" disabled hidden>-- Выберите страну / статус --</option>
            {Object.entries(CITIZENSHIP_CONFIG).map(([key, config]) => (
              <option key={key} value={key}>
                {config.label}
              </option>
            ))}
          </select>
        </div>

        {/* Кнопка экспорта PDF под выбором гражданства */}
        {citizenship !== '' && (
          <div className="export-pdf-wrapper">
            <button 
              className="export-pdf-btn" 
              onClick={exportToPDF}
              disabled={isExporting}
            >
              <Download size={16} />
              <span>{isExporting ? 'Создание PDF...' : 'Скачать памятку PDF'}</span>
            </button>
          </div>
        )}

        {/* Контент для экспорта в PDF */}
        <div ref={contentRef} className="pdf-export-content">
          {citizenship !== '' ? (
            <>
              {/* Шаги легализации с чекбоксами для сайта */}
              <div className="steps-list-vertical">
                {filteredSteps.map((step, index) => {
                  const isCompleted = !!checkedSteps[step.id];
                  const displayId = String(index + 1).padStart(2, '0');
                  const isStepFree = step.id >= 6 || String(step.id).startsWith('combined') || step.price?.toLowerCase() === 'бесплатно';

                  return (
                    <div
                      key={step.id}
                      className={`step-row-card ${isCompleted ? 'completed' : ''}`}
                      onClick={() => toggleStep(step.id)}
                    >
                      <div className="step-row-left">
                        <div className="step-number">{displayId}</div>
                        <div className="step-row-content">
                          <div className="step-title">{step.title}</div>
                          <div className="step-details">{step.details}</div>
                          
                          {step.address && (
                            <div className="step-address">
                              <MapPin size={12} />
                              <span>{step.address}</span>
                            </div>
                          )}
                        </div>
                      </div>

                      <div className="step-row-right">
                        {step.price && !isStepFree && (
                          <div className="step-meta">
                            <span className="step-price-label">Стоимость:</span>
                            <span className="step-price">{step.price}</span>
                          </div>
                        )}
                        {isStepFree && (
                          <div className="step-meta">
                            <span className="step-price-label">Стоимость:</span>
                            <span className="step-free">Бесплатно</span>
                          </div>
                        )}
                        <div className={`step-checkbox ${isCompleted ? 'checked' : ''}`}>
                          {isCompleted && <Check size={14} strokeWidth={3} />}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* Разрыв страницы перед описательным блоком */}
              <div className="pdf-page-break"></div>

              {/* Описательный блок */}
              <div className="warning-card pdf-warning">
                <p className="warning-text">
                  <AlertTriangle size={16} />
                  <span>Каждый новый въезд в РФ аннулирует старую регистрацию. По прибытии нужно оформлять её заново.</span>
                </p>
                <p className="warning-text">
                  <HelpCircle size={16} />
                  <span>Для индивидуальной консультации по визовым и миграционным вопросам обращайтесь к специалистам ОПВС.</span>
                </p>
                <p className="location-text">
                  <MapPin size={16} />
                  <span>ТЮМЕНСКИЙ ГОСУДАРСТВЕННЫЙ УНИВЕРСИТЕТ • ОПВС СОЦГУМ: ул. Ленина, 23</span>
                </p>
                <p className="disclaimer-text">
                  <CalendarIcon />
                  <span>Данные актуальны только на 2026 год. Информация может изменяться, следите за обновлениями.</span>
                </p>
              </div>
            </>
          ) : (
            <div className="select-prompt-placeholder">
              <p>Пожалуйста, выберите ваше гражданство или статус выше, чтобы сформировать персональный список шагов легализации.</p>
            </div>
          )}
        </div>
      </div>
    </section>
  );
};

export default MigrationGuide;