import React from 'react';
import './Hero.css';

const Hero = ({ language }) => {
  const content = {
    RU: {
      badge: 'Основы российской государственности',
      title: 'Тюмень: от стереотипа к реальности',
      description: 'Первый русский город Сибири — модельный регион, доказывающий, что можно быть одновременно историческим, современным и интегрированным в общероссийское пространство.',
      btn1: 'Исследование',
      btn2: 'Карта мест',
      stats: [
        { number: '80%', label: 'ожиданий оправдались' },
        { number: '137', label: 'иностранных студентов' },
        { number: '58.8%', label: 'сарафанное радио' }
      ]
    },
    EN: {
      badge: 'Fundamentals of Russian Statehood',
      title: 'Tyumen: From Stereotype to Reality',
      description: 'The first Russian city in Siberia — a model region proving that one can be simultaneously historical, modern, and integrated into the all-Russian space.',
      btn1: 'Research',
      btn2: 'Map',
      stats: [
        { number: '80%', label: 'expectations met' },
        { number: '137', label: 'international students' },
        { number: '58.8%', label: 'word of mouth' }
      ]
    }
  };

  const data = content[language];

  return (
    <section className="hero">
      <div className="container">
        <div className="hero-content">
          <div className="hero-badge">{data.badge}</div>
          <h1 className="hero-title">{data.title}</h1>
          <div className="hero-divider"></div>
          <p className="hero-description">{data.description}</p>
          <div className="hero-buttons">
            <a href="#research" className="btn-primary">{data.btn1}</a>
            <a href="#map" className="btn-secondary">{data.btn2}</a>
          </div>
        </div>
        <div className="hero-stats">
          {data.stats.map((stat, idx) => (
            <div key={idx} className="stat-block">
              <div className="stat-number">{stat.number}</div>
              <div className="stat-label">{stat.label}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Hero;