import React, { useState, useEffect, useRef } from 'react';

const AnimatedCounter = ({ targetValue, suffix = '%', duration = 1500, startDelay = 0, onProgress, isActive }) => {
  const [count, setCount] = useState(0);
  const [hasAnimated, setHasAnimated] = useState(false);
  const elementRef = useRef(null);
  const animationRef = useRef(null);
  const frameRef = useRef(null);

  useEffect(() => {
    if (isActive && !hasAnimated) {
      setHasAnimated(true);
      startAnimation();
    }
  }, [isActive]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && !hasAnimated) {
          setHasAnimated(true);
          startAnimation();
          observer.disconnect();
        }
      },
      { threshold: 0.1 }
    );

    if (elementRef.current && !isActive) {
      observer.observe(elementRef.current);
    }

    return () => observer.disconnect();
  }, [hasAnimated, isActive]);

  const startAnimation = () => {
    if (animationRef.current) {
      cancelAnimationFrame(animationRef.current);
    }

    const timer = setTimeout(() => {
      let startValue = 0;
      const startTime = performance.now();
      
      const updateCounter = (currentTime) => {
        const elapsed = currentTime - startTime;
        const progress = Math.min(elapsed / duration, 1);
        const easedProgress = 1 - Math.pow(1 - progress, 2);
        const currentValue = targetValue * easedProgress;
        
        setCount(currentValue);
        
        if (onProgress) {
          onProgress(currentValue);
        }
        
        if (progress < 1) {
          frameRef.current = requestAnimationFrame(updateCounter);
        } else {
          setCount(targetValue);
          if (onProgress) {
            onProgress(targetValue);
          }
        }
      };
      
      frameRef.current = requestAnimationFrame(updateCounter);
    }, startDelay);

    return () => {
      clearTimeout(timer);
      if (frameRef.current) {
        cancelAnimationFrame(frameRef.current);
      }
    };
  };

  return (
    <span ref={elementRef} className="animated-counter">
      {Math.floor(count)}{suffix}
    </span>
  );
};

export default AnimatedCounter;